public class EditDistance {

    public int minEditDistance(String a, String b) {
        int m = a.length(), n = b.length();
        int[][] dp = new int[m+1][n+1];

        // Base cases: converting prefix of a to empty, or empty to prefix of b
        for (int i = 0; i <= m; i++) dp[i][0] = i;
        for (int j = 0; j <= n; j++) dp[0][j] = j;

        for (int i = 1; i <= m; i++) {
            for (int j = 1; j <= n; j++) {
                if (a.charAt(i-1) == b.charAt(j-1)) {
                    dp[i][j] = dp[i-1][j-1]; // no operation needed
                } else {
                    // TODO: dp[i][j] = 1 + min of (dp[i-1][j-1], dp[i-1][j], dp[i][j-1])
                    // substitute: dp[i-1][j-1], delete: dp[i-1][j], insert: dp[i][j-1]
                }
            }
        }
        return dp[m][n];
    }

    public static void main(String[] args) {
        EditDistance ed = new EditDistance();
        System.out.println("horse -> ros:         " + ed.minEditDistance("horse", "ros"));
        System.out.println("intention -> execution: " + ed.minEditDistance("intention", "execution"));
        System.out.println("abc -> abc:            " + ed.minEditDistance("abc", "abc"));
        System.out.println("abc -> :               " + ed.minEditDistance("abc", ""));
    }
}

