    public int[] maxSubarrayWithIndices(int[] arr) {
        int maxSoFar = arr[0], maxEnd = arr[0];
        int start = 0, end = 0, tempStart = 0;
        for (int i = 1; i < arr.length; i++) {
            if (arr[i] > maxEnd + arr[i]) {
                maxEnd = arr[i];
                tempStart = i;
            } else {
                maxEnd = maxEnd + arr[i];
            }
            if (maxEnd > maxSoFar) {
                maxSoFar = maxEnd;
                start = tempStart;
                end = i;
            }
        }
        return new int[]{maxSoFar, start, end};
    }

    public static void main(String[] args) {
        MaxSubarray ms = new MaxSubarray();
        System.out.println("Max sum [-2,1,-3,4,-1,2,1,-5,4]: " + ms.maxSubarraySum(new int[]{-2,1,-3,4,-1,2,1,-5,4}));
        int[] r = ms.maxSubarrayWithIndices(new int[]{-2,1,-3,4,-1,2,1,-5,4});
        System.out.println("Max sum=" + r[0] + ", start=" + r[1] + ", end=" + r[2]);
        System.out.println("All negatives [-3,-1,-2]: " + ms.maxSubarraySum(new int[]{-3,-1,-2}));
    }
}

public class PalindromePartition {

    public int minCuts(String s) {
        int n = s.length();
        // Step 1: isPalin[i][j] = true if s[i..j] is a palindrome
        boolean[][] isPalin = new boolean[n][n];
        for (int i = 0; i < n; i++) isPalin[i][i] = true;
        for (int i = 0; i < n - 1; i++) isPalin[i][i+1] = (s.charAt(i) == s.charAt(i+1));
        for (int len = 3; len <= n; len++)
            for (int i = 0; i <= n - len; i++) {
                int j = i + len - 1;
                isPalin[i][j] = (s.charAt(i) == s.charAt(j)) && isPalin[i+1][j-1];
            }

        // Step 2: cuts[i] = min cuts for s[0..i]
        int[] cuts = new int[n];
        for (int i = 0; i < n; i++) {
            if (isPalin[0][i]) {
                cuts[i] = 0; // whole prefix is palindrome
            } else {
                cuts[i] = i; // worst case: cut before each character
                for (int j = 1; j <= i; j++) {
                    if (isPalin[j][i]) {
                        // TODO: cuts[i] = Math.min(cuts[i], cuts[j-1] + 1)
                    }
                }
            }
        }
        return cuts[n-1];
    }

    public static void main(String[] args) {
        PalindromePartition pp = new PalindromePartition();
        System.out.println("aab:      " + pp.minCuts("aab"));   // a|a|b or aa|b → 1
        System.out.println("abacaba:  " + pp.minCuts("abacaba")); // whole is palindrome → 0
        System.out.println("abcde:    " + pp.minCuts("abcde")); // no palindromes > len 1 → 4
        System.out.println("aabaa:    " + pp.minCuts("aabaa")); // whole is palindrome → 0
    }
}
